mapper.select:
SELECT COUNT(*)
  FROM BL_PRODUCT_FAVORITES
 WHERE MEMBER_ID = #{memberId}
   AND PRODUCT_ID = #{productId}

mapper.delete:
DELETE FROM BL_PRODUCT_FAVORITES
 WHERE MEMBER_ID = #{memberId}
   AND PRODUCT_ID = #{productId}

DELETE FROM BL_PRODUCT_RATINGS
 WHERE MEMBER_ID = #{memberId,jdbcType=NUMERIC}
   AND PRODUCT_ID = #{productId,jdbcType=NUMERIC}

DELETE FROM BL_RECOMMENDATION_FEEDBACK
 WHERE MEMBER_ID = #{memberId}
   AND PRODUCT_ID = #{productId}
